import{_ as a}from"./chunks/文件受限图.DsG20F9s.js";import{_ as i,o as t,c as l,a2 as d}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Image Moderation او Access Mode","description":"","frontmatter":{},"headers":[],"relativePath":"ps/Safety/image-moderation-and-access-mode.md","filePath":"ps/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),s={name:"ps/Safety/image-moderation-and-access-mode.md"};function r(o,e,n,c,m,p){return t(),l("div",null,[...e[0]||(e[0]=[d('<h1 id="image-moderation-او-access-mode" tabindex="-1">Image Moderation او Access Mode <a class="header-anchor" href="#image-moderation-او-access-mode" aria-label="Permalink to &quot;Image Moderation او Access Mode&quot;">​</a></h1><p>Image moderation upload شوو images ته age ratings ورکوي. Access mode کنټرولوي چې کوم ratings د public access له لارې ښکاره شي.</p><p>دا public gallery، public file URLs او random image API اغېزمنوي. admin panel نه محدودوي. administrators لا هم ټول files کتلی او manage کولی شي.</p><h2 id="چېرته-یې-تنظیم-کړئ" tabindex="-1">چېرته یې تنظیم کړئ <a class="header-anchor" href="#چېرته-یې-تنظیم-کړئ" aria-label="Permalink to &quot;چېرته یې تنظیم کړئ&quot;">​</a></h2><p>admin panel پرانیزئ، بیا دې ځای ته لاړ شئ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>اصلي settings دا دي:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="access-mode-څه-کوي" tabindex="-1">Access Mode څه کوي <a class="header-anchor" href="#access-mode-څه-کوي" aria-label="Permalink to &quot;Access Mode څه کوي&quot;">​</a></h2><p>Access mode ټاکي چې کوم age ratings په public ډول ښکاره کېدای شي.</p><p>اوسني modes:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>په public ډول visible ratings</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>یوازې General</td></tr></tbody></table><p>Default یې Adult mode دی.</p><p>د private sites یا mature content لرونکو sites لپاره Adult mode مناسب کېدای شي. د لا محتاط public gallery لپاره Youth، Teen یا Child mode وټاکئ.</p><h2 id="enable-moderation-څه-کوي" tabindex="-1">Enable Moderation څه کوي <a class="header-anchor" href="#enable-moderation-څه-کوي" aria-label="Permalink to &quot;Enable Moderation څه کوي&quot;">​</a></h2><p>کله چې moderation فعال وي، ImgBed د upload پر وخت ټاکل شوی moderation provider غږوي او موندل شوی age rating خوندي کوي.</p><p>اصلي ratings:</p><table tabindex="0"><thead><tr><th>Rating</th><th>معنا</th></tr></thead><tbody><tr><td>General</td><td>خوندي public content</td></tr><tr><td>R12</td><td>لږ حساس content</td></tr><tr><td>R16</td><td>منځنی حساس content</td></tr><tr><td>R18</td><td>adult content</td></tr></tbody></table><p>moderation result د public access د پرېکړې پر وخت کارېږي.</p><p>که moderation فعال نه وي، یا زاړه files rating ونه لري، هغه files unrated ګڼل کېږي. unrated files یوازې د rating د نشتوالي له امله په اتومات ډول له public gallery یا random image API نه لرې کېږي.</p><h2 id="د-moderation-provider-ټاکل" tabindex="-1">د Moderation Provider ټاکل <a class="header-anchor" href="#د-moderation-provider-ټاکل" aria-label="Permalink to &quot;د Moderation Provider ټاکل&quot;">​</a></h2><p>شته providers:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>هر provider بېلابېلې اړتیاوې لري:</p><ul><li>moderatecontent.com عموما API Key غواړي.</li><li>nsfwjs عموما API endpoint URL غواړي.</li><li>Sightengine API user او API secret غواړي.</li></ul><p>د خپل account، availability او detection quality له مخې یې وټاکئ. که moderation فعال وي او سم تنظیم شوی وي، ImgBed د upload پر وخت د image rating لیکلو هڅه کوي.</p><h2 id="پر-public-gallery-اغېز" tabindex="-1">پر Public Gallery اغېز <a class="header-anchor" href="#پر-public-gallery-اغېز" aria-label="Permalink to &quot;پر Public Gallery اغېز&quot;">​</a></h2><p>public gallery د access mode له مخې files filter کوي.</p><p>بېلګې:</p><ul><li>Adult mode: R18 images ښکاره کېدای شي.</li><li>Youth mode: R18 images پټېږي.</li><li>Teen mode: R16 او R18 images پټېږي.</li><li>Child mode: یوازې General images ښکاره کېږي.</li></ul><p>دا یوازې عادي public access اغېزمنوي. admin panel لا هم ټول files ښيي.</p><h2 id="پر-public-file-urls-اغېز" tabindex="-1">پر Public File URLs اغېز <a class="header-anchor" href="#پر-public-file-urls-اغېز" aria-label="Permalink to &quot;پر Public File URLs اغېز&quot;">​</a></h2><p>Public file URLs هغه مستقیم image links دي چې visitors یې پرانیزي.</p><p>که د فایل rating د اوسني access mode له خوا allowed وي، ImgBed اصلي image ورکوي.</p><p>که rating له allowed level لوړ وي، عادي public access اصلي image نه ورکوي. پر ځای یې ImgBed configured blocked result یا د restricted access لپاره ټاکل شوی بدیل image ښکاره کوي.</p><p>بېلګه:</p><ul><li>اوسنی mode Child mode دی.</li><li>یو image R18 rated دی.</li><li>visitor public URL مستقیم پرانیزي.</li><li>ImgBed هغه visitor ته اصلي R18 image نه ورکوي.</li></ul><p><img src="'+a+'" alt="Restricted file image" loading="lazy"></p><p>administrators چې files په admin panel کې ګوري، له دې restriction نه اغېزمنېږي.</p><h2 id="پر-random-image-api-اغېز" tabindex="-1">پر Random Image API اغېز <a class="header-anchor" href="#پر-random-image-api-اغېز" aria-label="Permalink to &quot;پر Random Image API اغېز&quot;">​</a></h2><p>random image API هم د access mode له مخې خپل candidate pool filter کوي.</p><p>په Child mode کې، random images یوازې له General-rated files څخه ټاکل کېږي.</p><p>په Youth mode کې، random images له General، R12 او R16 files څخه راتلای شي، خو له R18 files څخه نه.</p><p>دا random image API له دې منع کوي چې د public gallery restrictions bypass کړي.</p><h2 id="له-list-rules-سره-اړیکه" tabindex="-1">له List Rules سره اړیکه <a class="header-anchor" href="#له-list-rules-سره-اړیکه" aria-label="Permalink to &quot;له List Rules سره اړیکه&quot;">​</a></h2><p>Access mode یوازینی public access rule نه دی. دا د allow/block list rules سره یو ځای کار کوي.</p><p>په ساده ډول:</p><ul><li>Allowlisted content لومړی public ګڼل کېږي.</li><li>Blocklisted content عادي visitors مستقیم نه شي کتلی.</li><li>هغه content چې په هېڅ list کې نه وي، بیا د access mode له مخې check کېږي.</li></ul><p>که image هم د age rating او هم د list rules له مخې restricted وي، عادي visitors لا هم اصلي فایل مستقیم نه شي کتلی.</p><h2 id="سپارښتل-شوي-settings" tabindex="-1">سپارښتل شوي Settings <a class="header-anchor" href="#سپارښتل-شوي-settings" aria-label="Permalink to &quot;سپارښتل شوي Settings&quot;">​</a></h2><p>د public sites لپاره:</p><ul><li>moderation فعال کړئ.</li><li>داسې access mode وټاکئ چې د site له audience سره برابر وي.</li><li>د all-age visitors لپاره Child mode یا Teen mode وکاروئ.</li><li>که نه غواړئ mature content په public ډول ښکاره شي، Adult mode مه کاروئ.</li><li>په admin panel کې file ratings وګورئ او د اړتیا پر وخت یې manually بدل کړئ.</li></ul><p>د private یا personal sites لپاره:</p><ul><li>Adult mode عموما مناسب دی.</li><li>که ګټور وي، moderation فعال کړئ.</li><li>په admin panel کې ratings وګورئ او د اړتیا پر وخت یې adjust کړئ.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="د-access-mode-له-بدلولو-وروسته-files-له-admin-panel-څخه-ورکېږي؟" tabindex="-1">د Access Mode له بدلولو وروسته Files له Admin Panel څخه ورکېږي؟ <a class="header-anchor" href="#د-access-mode-له-بدلولو-وروسته-files-له-admin-panel-څخه-ورکېږي؟" aria-label="Permalink to &quot;د Access Mode له بدلولو وروسته Files له Admin Panel څخه ورکېږي؟&quot;">​</a></h3><p>نه.</p><p>Access mode یوازې عادي public access اغېزمنوي. admin panel نه اغېزمنوي.</p><h3 id="ولې-public-gallery-له-child-mode-وروسته-لږ-images-وښودل؟" tabindex="-1">ولې Public Gallery له Child Mode وروسته لږ Images وښودل؟ <a class="header-anchor" href="#ولې-public-gallery-له-child-mode-وروسته-لږ-images-وښودل؟" aria-label="Permalink to &quot;ولې Public Gallery له Child Mode وروسته لږ Images وښودل؟&quot;">​</a></h3><p>Child mode یوازې General-rated files ته public display اجازه ورکوي. R12، R16 او R18 files filter کېږي.</p><h3 id="public-urls-لا-هم-adult-images-پرانیستلی-شي؟" tabindex="-1">Public URLs لا هم Adult Images پرانیستلی شي؟ <a class="header-anchor" href="#public-urls-لا-هم-adult-images-پرانیستلی-شي؟" aria-label="Permalink to &quot;Public URLs لا هم Adult Images پرانیستلی شي؟&quot;">​</a></h3><p>که اوسنی access mode هغه rating ته اجازه ورنه کړي، عادي public URLs اصلي image نه ورکوي.</p><h3 id="random-image-api-restricted-images-ورکولی-شي؟" tabindex="-1">Random Image API restricted images ورکولی شي؟ <a class="header-anchor" href="#random-image-api-restricted-images-ورکولی-شي؟" aria-label="Permalink to &quot;Random Image API restricted images ورکولی شي؟&quot;">​</a></h3><p>نه.</p><p>random image API candidates د اوسني access mode له مخې filter کوي.</p><h3 id="د-زړو-unrated-images-سره-څه-کېږي؟" tabindex="-1">د زړو Unrated Images سره څه کېږي؟ <a class="header-anchor" href="#د-زړو-unrated-images-سره-څه-کېږي؟" aria-label="Permalink to &quot;د زړو Unrated Images سره څه کېږي؟&quot;">​</a></h3><p>unrated images یوازې د moderation results د نشتوالي له امله په اتومات ډول نه پټېږي. وروسته یې ratings په admin panel کې بدلولای شئ.</p>',67)])])}const b=i(s,[["render",r]]);export{h as __pageData,b as default};
